import React, { useState } from 'react';
import { useCart, useWishlist } from '../context/CartContext';
import { homeNewArrivals } from '../data/productsData';
import './NewArrivals.css';

function Stars({ count }) {
  return (
    <span className="na-stars">
      {Array.from({ length: 5 }).map((_, i) => (
        <span key={i} className={i < count ? 'star filled' : 'star'}>★</span>
      ))}
    </span>
  );
}

export default function NewArrivals({ onQuickView, onAddedToCart }) {
  const { addToCart } = useCart();
  const { toggleWishlist, isWishlisted } = useWishlist();
  const [hovered, setHovered] = useState(null);

  function handleAdd(p) {
    addToCart(p);
    onAddedToCart && onAddedToCart(p);
  }

  return (
    <section className="na-section">
      {/* Header */}
      <div className="na-header">
        <h2 className="na-heading">New Arrivals</h2>
        <p className="na-sub">
          New Arrivals" means recently added or newly available items, usually in a
          store, website, or collection.
        </p>
      </div>

      {/* Product Grid */}
      <div className="na-grid">
        {homeNewArrivals.map((p) => (
          <div
            key={p.id}
            className="na-card"
            onMouseEnter={() => setHovered(p.id)}
            onMouseLeave={() => setHovered(null)}
          >
            {/* Image */}
            <div
              className="na-img-wrap"
              onClick={() => onQuickView && onQuickView(p)}
              style={{ cursor: 'pointer' }}
            >
              <img src={p.img} alt={p.name} className="na-img" />
              {hovered === p.id && (
                <div className="na-hover-overlay">
                  <button
                    className="na-quick-view-btn"
                    onClick={e => { e.stopPropagation(); onQuickView && onQuickView(p); }}
                  >
                    Quick View
                  </button>
                </div>
              )}
            </div>

            {/* Info */}
            <div className="na-info">
              <div className="na-name-row">
                <span className="na-name">{p.name}</span>
                <Stars count={p.stars} />
              </div>
              <span className="na-brand">{p.brand || 'Al Karam'}</span>
              <span className="na-reviews">({p.reviews || '4.1k'}) Customer Reviews</span>
              <div className="na-price-row">
                <span className="na-price">${p.price}</span>
                <span className="na-sold">Almost Sold Out</span>
              </div>
              {hovered === p.id && (
                <button
                  className="na-add-btn"
                  onClick={() => handleAdd(p)}
                >
                  ADD TO CART
                </button>
              )}
            </div>
          </div>
        ))}
      </div>
    </section>
  );
}
